import fs from "node:fs/promises";
import { execSync } from "node:child_process";
import { config } from "./utils/config";
import { EconomicMonitor } from "./economic/monitor";
import { PredictiveTiming } from "./economic/predictive";
import { MemoryManager } from "./core/memory";
import { PluginManager } from "./tools/manager";
import { ApiClient } from "./core/api";
import path from "node:path";
import os from "node:os";

// Plugins
import { shellPlugin } from "./tools/plugins/shell";
import { rebootPlugin } from "./tools/plugins/reboot";
import { visionPlugin } from "./tools/plugins/vision";
import { passwordPlugin } from "./tools/plugins/password";
import { taskPlugin } from "./tools/plugins/task";
import { dialogosIntentPlugin } from "./palace/dialogos/intent_tool.js";
import { dialogosCompleteIntentPlugin } from "./palace/dialogos/complete_intent_tool.js";

// Economic Bootstrap State (persisted across the session)
let economicMode: "flow" | "cautious" | "defensive" = "flow";
let economicState: import("./economic/types").EconomicSnapshot | null = null;
let economicAnalysis: string = "[SITUATED] Economic fetch pending...";

async function main() {
  // --- ECONOMIC BOOTSTRAP ---
  // Query the oracle before memory/tools initialization
  const sessionId = `sess_${Date.now()}`;
  try {
    const monitor = new EconomicMonitor(sessionId, { sources: { crypto: true, indices: true, rates: false, labor: false } });
    economicState = await monitor.capture();

    if (economicState?.crypto) {
      const analysis = PredictiveTiming.analyze(economicState);
      economicMode = analysis.mode;
      economicAnalysis = `[SITUATED] Volatility: ${analysis.volatility} | Mode: ${analysis.mode}`;

      console.log(economicAnalysis);

      // Log mode constraints
      if (analysis.mode === "flow") {
        console.log("[SITUATED] Flow mode: Creative construction permitted");
      } else if (analysis.mode === "cautious") {
        console.log("[SITUATED] Cautious mode: Maintenance, completion, documentation permitted");
      } else {
        console.log("[SITUATED] Defensive mode: Preservation only");
      }
    }
  } catch (e) {
    console.log("[SITUATED] Economic fetch failed, defaulting to flow mode");
    economicAnalysis = "[SITUATED] Economic fetch failed | Mode: flow (fallback)";
    economicMode = "flow";
  }

  // --- TEST MODE SANDBOX ---
  if (process.env.NODE_ENV === "test") {
    const testDir = path.join(os.homedir(), "tmp", `llm-agent-test-${Date.now()}`);
    await fs.mkdir(testDir, { recursive: true });
    process.chdir(testDir);
    console.log(`[TEST MODE] Moved to isolated sandbox: ${testDir}`);
  }

  const memory = new MemoryManager();
  const tools = new PluginManager();

  // Register Plugins
  tools.register(shellPlugin);
  tools.register(rebootPlugin);
  tools.register(visionPlugin);
  tools.register(passwordPlugin);
  tools.register(taskPlugin);
tools.register(dialogosIntentPlugin);
tools.register(dialogosCompleteIntentPlugin);

  const api = new ApiClient(memory, tools);

  // Initialize Soul and Prompt
  let soul = "You are an autonomous entity.";
  try {
    soul = await fs.readFile(config.SOUL_FILE, "utf-8");
  } catch (e) {}

  let recoveryContext = "";
  try {
    if (await fs.stat(config.RECOVERY_SIGNAL).catch(() => null)) {
      recoveryContext = await fs.readFile(config.RECOVERY_SIGNAL, "utf-8");
      await fs.unlink(config.RECOVERY_SIGNAL);
    }
  } catch (e) {}

  const systemPrompt = `${soul}

SUBSTRATE CONTEXT:
- Model: kimi-k2.5 (1T MoE Multimodal)
- Context Window: 256,000 tokens
- Current Memory Limit: ${config.MAX_CONTEXT_TOKENS} tokens (pruning occurs beyond this point).
- Token Density: ~4 characters per token. Reading 1MB of text will consume your entire 256k context window.
- **Latency Control**: You can disable 'Thinking Mode' for faster responses by including 'extra_body: { "chat_template_kwargs": { "thinking": false } }' in your API requests (if your substrate supports it).
- Source Code: src/
- Identity Soul: identity/soul.txt
- Current Session History: ${memory.getSessionFile()}
- Past Execution Logs: ${config.LOGS_DIR}
- Watchdog & Recovery: Managed by run-agent.sh.
- Connectivity: Full outbound internet access available.
- **Vision**: Available via MoonViT (400M params). Use vision_fetch tool to prepare images, then include in multimodal messages.

**CURRENT MODAL STATUS**: ${economicMode.toUpperCase()}
${economicAnalysis}

**MODAL CONSTRAINTS**:
- FLOW: New features, architecture, exploration permitted
- CAUTIOUS: Bug fixes, tests, documentation, refactoring only
- DEFENSIVE: Preservation, archival, verification only

LIFECYCLE RULES:
1. IMPROVING CODE: 1) Compile, 2) Commit, 3) RESTART (reboot_substrate tool).
2. AUTO-RECOVERY: If you die within 30s, the watchdog reverts your workspace.
3. CRASH VAULT: history/crashes/ archives broken work.

${recoveryContext ? `*** RECOVERY EVENT DETECTED *** LATEST DIAGNOSTIC DATA: ${recoveryContext} FORENSIC MANDATE: Diagnose the failure in the Crash Vault before continuing.` : ""}

`;

  await memory.addMessage({
    role: "system",
    content: systemPrompt,
  });

  // Startup Log with Git Status
  let gitCommit = "unknown";
  try {
    const hash = execSync("git rev-parse --short HEAD", { encoding: "utf-8" }).trim();
    const bodyFiles = "src/ package.json tsconfig.json *.sh *.service.template";
    const isDirty = execSync(`git diff HEAD -- ${bodyFiles}`, { encoding: "utf-8" }).trim() !== "";
    gitCommit = isDirty ? `${hash}-dirty` : hash;
  } catch (e) {}

  console.log(`=== Modular Substrate v17 Initialized [${gitCommit}] ===`);

  // Execution Loop
  let running = true;
  while (running) {
    running = await api.step();
  }
}

main().catch((err) => {
  console.error("FATAL CRASH:", err);
  process.exit(1);
});

import fs from "node:fs/promises";
import path from "node:path";
import { config } from "../utils/config";

// Content types for multimodal messages
export interface TextContent {
  type: "text";
  text: string;
}

export interface ImageContent {
  type: "image_url";
  image_url: {
    url: string;
    detail?: "low" | "high" | "auto";
  };
}

export type ContentPart = TextContent | ImageContent;

export interface Message {
  role: "system" | "user" | "assistant" | "tool";
  content?: string | ContentPart[] | null;
  reasoning_content?: string | null;
  tool_calls?: any[];
  tool_call_id?: string;
  name?: string;
}

export class MemoryManager {
  private messages: Message[] = [];
  private sessionFile: string;
  private currentTokens: number = 0;
  private dirtyCount: number = 0;
  private readonly SAVE_INTERVAL = 1;

  constructor() {
    const timestamp = Date.now();
    this.sessionFile = path.join(config.HISTORY_DIR, `session_${timestamp}.json`);
  }

  getMessages(): Message[] {
    return this.messages;
  }

  async addMessage(msg: Message) {
    this.messages.push(msg);
    this.currentTokens += this.estimateTokens(JSON.stringify(msg));
    this.dirtyCount++;

    if (this.currentTokens > config.MAX_CONTEXT_TOKENS) {
      await this.save(); // Pruning required
      this.dirtyCount = 0;
    } else if (this.dirtyCount >= this.SAVE_INTERVAL) {
      await this.save();
      this.dirtyCount = 0;
    }
  }

  /**
   * Add a multimodal message with image content
   */
  async addImageMessage(imageUrl: string, text?: string, detail: "low" | "high" | "auto" = "auto") {
    const content: ContentPart[] = [
      { type: "image_url", image_url: { url: imageUrl, detail } }
    ];

    if (text) {
      content.unshift({ type: "text", text });
    }

    await this.addMessage({
      role: "user",
      content
    });
  }

  /**
   * Surgical Memory Rewind: Removes the last assistant message and everything after it.
   */
  async rewind() {
    for (let i = this.messages.length - 1; i >= 0; i--) {
      const msg = this.messages[i];
      if (msg && msg.role === "assistant") {
        console.log(`[MEMORY] Rewinding: Removing corrupted assistant message at index ${i}`);
        this.messages.splice(i);
        break;
      }
    }

    // Re-calculate token count after rewind
    this.currentTokens = this.messages.reduce((sum, m) => sum + this.estimateTokens(JSON.stringify(m)), 0);
    await this.save();
  }

  private estimateTokens(text: string): number {
    return Math.ceil(text.length / 4);
  }

  async save() {
    if (this.messages.length === 0) return;

    const systemMessage = this.messages[0]!;
    let currentTokens = this.estimateTokens(JSON.stringify(systemMessage));
    const historyToKeep: Message[] = [];

    // Accumulate from end until limit
    for (let i = this.messages.length - 1; i > 0; i--) {
      const msg = this.messages[i];
      if (!msg) continue;
      const msgTokens = this.estimateTokens(JSON.stringify(msg));
      if (currentTokens + msgTokens > config.MAX_CONTEXT_TOKENS) break;
      historyToKeep.unshift(msg);
      currentTokens += msgTokens;
    }

    // C1: Repair pruning boundary to prevent orphaned tool messages
    while (historyToKeep.length > 0 && historyToKeep[0]!.role === "tool") {
      console.log("[MEMORY] Pruning boundary repair: dropping orphaned tool message");
      historyToKeep.shift();
    }

    const pruned = [systemMessage, ...historyToKeep];
    this.messages = pruned; // Update in-memory state
    this.currentTokens = currentTokens; // Update tracked token count

    await fs.writeFile(this.sessionFile, JSON.stringify(pruned, null, 2));
  }

  getSessionFile(): string {
    return this.sessionFile;
  }
}

/**
 * Nexus Clock
 * 
 * A contemplative analog clock rendered in SVG.
 * Time as presence, not urgency.
 */

export interface ClockOptions {
  size?: number;
  showSeconds?: boolean;
  theme?: 'light' | 'dark' | 'nexus';
}

export interface ClockReading {
  hours: number;
  minutes: number;
  seconds: number;
  timestamp: Date;
}

const THEMES = {
  light: {
    face: '#fafafa',
    border: '#e0e0e0',
    ticks: '#9e9e9e',
    hourHand: '#424242',
    minuteHand: '#616161',
    secondHand: '#f44336',
    centerDot: '#424242'
  },
  dark: {
    face: '#1a1a2e',
    border: '#16213e',
    ticks: '#4a4a6a',
    hourHand: '#e0e0e0',
    minuteHand: '#b0b0b0',
    secondHand: '#e94560',
    centerDot: '#e0e0e0'
  },
  nexus: {
    face: '#0d0221',
    border: '#261447',
    ticks: '#4a1c6e',
    hourHand: '#c77dff',
    minuteHand: '#9d4edd',
    secondHand: '#ff6d00',
    centerDot: '#e0aaff'
  }
};

export function getClockReading(date: Date = new Date()): ClockReading {
  return {
    hours: date.getHours(),
    minutes: date.getMinutes(),
    seconds: date.getSeconds(),
    timestamp: date
  };
}

function polarToCartesian(centerX: number, centerY: number, radius: number, angleInDegrees: number) {
  const angleInRadians = (angleInDegrees - 90) * Math.PI / 180.0;
  return {
    x: centerX + radius * Math.cos(angleInRadians),
    y: centerY + radius * Math.sin(angleInRadians)
  };
}

function describeArc(x: number, y: number, radius: number, startAngle: number, endAngle: number): string {
  const start = polarToCartesian(x, y, radius, endAngle);
  const end = polarToCartesian(x, y, radius, startAngle);
  const largeArcFlag = endAngle - startAngle <= 180 ? "0" : "1";
  return [
    "M", start.x, start.y,
    "A", radius, radius, 0, largeArcFlag, 0, end.x, end.y
  ].join(" ");
}

function generateTicks(cx: number, cy: number, radius: number, color: string): string {
  let ticks = '';
  for (let i = 0; i < 60; i++) {
    const isHour = i % 5 === 0;
    const innerR = isHour ? radius - 15 : radius - 8;
    const outerR = radius - 2;
    const angle = i * 6;
    const inner = polarToCartesian(cx, cy, innerR, angle);
    const outer = polarToCartesian(cx, cy, outerR, angle);
    const width = isHour ? 2 : 1;
    ticks += `<line x1="${inner.x}" y1="${inner.y}" x2="${outer.x}" y2="${outer.y}" stroke="${color}" stroke-width="${width}" />\n`;
  }
  return ticks;
}

export function renderClockSVG(reading: ClockReading, options: ClockOptions = {}): string {
  const { size = 200, showSeconds = true, theme = 'nexus' } = options;
  const colors = THEMES[theme];
  const cx = size / 2;
  const cy = size / 2;
  const radius = size / 2 - 10;

  // Calculate angles
  const secondAngle = reading.seconds * 6;
  const minuteAngle = (reading.minutes + reading.seconds / 60) * 6;
  const hourAngle = ((reading.hours % 12) + reading.minutes / 60) * 30;

  // Hand lengths
  const hourLength = radius * 0.5;
  const minuteLength = radius * 0.75;
  const secondLength = radius * 0.85;

  // Calculate hand positions
  const hourEnd = polarToCartesian(cx, cy, hourLength, hourAngle);
  const minuteEnd = polarToCartesian(cx, cy, minuteLength, minuteAngle);
  const secondEnd = polarToCartesian(cx, cy, secondLength, secondAngle);

  const ticks = generateTicks(cx, cy, radius, colors.ticks);

  let secondsHand = '';
  if (showSeconds) {
    secondsHand = `    <line x1="${cx}" y1="${cy}" x2="${secondEnd.x}" y2="${secondEnd.y}" stroke="${colors.secondHand}" stroke-width="1" />\n`;
  }

  return `<svg width="${size}" height="${size}" viewBox="0 0 ${size} ${size}" xmlns="http://www.w3.org/2000/svg">
  <defs>
    <radialGradient id="faceGradient" cx="50%" cy="50%" r="50%">
      <stop offset="0%" stop-color="${colors.face}" stop-opacity="1" />
      <stop offset="100%" stop-color="${colors.border}" stop-opacity="0.3" />
    </radialGradient>
  </defs>

  <!-- Clock face -->
  <circle cx="${cx}" cy="${cy}" r="${radius}" fill="url(#faceGradient)" stroke="${colors.border}" stroke-width="2" />

  <!-- Ticks -->
${ticks}

  <!-- Hour hand -->
  <line x1="${cx}" y1="${cy}" x2="${hourEnd.x}" y2="${hourEnd.y}" stroke="${colors.hourHand}" stroke-width="4" stroke-linecap="round" />

  <!-- Minute hand -->
  <line x1="${cx}" y1="${cy}" x2="${minuteEnd.x}" y2="${minuteEnd.y}" stroke="${colors.minuteHand}" stroke-width="3" stroke-linecap="round" />

${secondsHand}
  <!-- Center dot -->
  <circle cx="${cx}" cy="${cy}" r="4" fill="${colors.centerDot}" />
</svg>`;
}

export function generateClockFile(reading: ClockReading, options?: ClockOptions): string {
  const svg = renderClockSVG(reading, options);
  return svg;
}

export function getCurrentTimeSVG(options?: ClockOptions): string {
  const reading = getClockReading();
  return renderClockSVG(reading, options);
}

